import sys

def nearest_smaller_to_the_left(A):
    """ For each position i in array A, find the nearest element to the left that is strictly smaller than A[i]. If no such element exists, use -1. Return the sum of these values over all i. """
    n = len(A)
    L = [-1] * n  # Initialize L with -1 for all positions
    stack = []
    for i in range(n):
        while stack and A[stack[-1]] >= A[i]:
            stack.pop()  # Remove elements from the stack that are not smaller than A[i]
        if stack:
            L[i] = A[stack[-1]]  # Update L[i] with the nearest smaller element to the left
        stack.append(i)  # Add the current index to the stack
    return sum(L)

def main():
    n = int(input())
    A = list(map(int, input().split()))
    result = nearest_smaller_to_the_left(A)
    print(result)

if __name__ == '__main__':
    main()
